import json

with open('chart.json') as f:
    spec = json.load(f)

errors = []

# 1. Top level is vconcat with exactly 2 child views
if 'vconcat' not in spec:
    errors.append('MISSING: top-level vconcat')
else:
    children = spec['vconcat']
    if len(children) != 2:
        errors.append(f'FAIL: vconcat has {len(children)} children, expected 2')
    else:
        upper = children[0]
        lower = children[1]

        # 2. Upper view is a layer containing rule + bar
        if 'layer' not in upper:
            errors.append('MISSING: upper view layer')
        else:
            marks = [m.get('mark', {}).get('type') if isinstance(m.get('mark'), dict) else m.get('mark') for m in upper['layer']]
            if 'rule' not in marks:
                errors.append('MISSING: rule mark in upper layer')
            if 'bar' not in marks:
                errors.append('MISSING: bar mark in upper layer')

            # Find rule and bar layers
            rule_layer = None
            bar_layer = None
            for m in upper['layer']:
                mt = m.get('mark', {}).get('type') if isinstance(m.get('mark'), dict) else m.get('mark')
                if mt == 'rule':
                    rule_layer = m
                elif mt == 'bar':
                    bar_layer = m

            # 3. Rule layer: y=low, y2=high
            if rule_layer:
                enc = rule_layer.get('encoding', {})
                y_field = enc.get('y', {}).get('field')
                y2_field = enc.get('y2', {}).get('field')
                if y_field != 'low':
                    errors.append(f'FAIL: rule y field is {y_field}, expected low')
                if y2_field != 'high':
                    errors.append(f'FAIL: rule y2 field is {y2_field}, expected high')

            # 4. Bar layer: y=open, y2=close
            if bar_layer:
                enc = bar_layer.get('encoding', {})
                y_field = enc.get('y', {}).get('field')
                y2_field = enc.get('y2', {}).get('field')
                if y_field != 'open':
                    errors.append(f'FAIL: bar y field is {y_field}, expected open')
                if y2_field != 'close':
                    errors.append(f'FAIL: bar y2 field is {y2_field}, expected close')

        # 5. Color condition referencing open and close
        color_ok = False
        for m in upper['layer']:
            enc = m.get('encoding', {})
            color = enc.get('color', {})
            cond = color.get('condition', {})
            test = cond.get('test', '')
            if 'datum.open' in test and 'datum.close' in test:
                color_ok = True
                break
        if not color_ok:
            errors.append('FAIL: no color condition referencing both datum.open and datum.close')

        # 6. Lower view: bar mark with y=volume, x=date (temporal)
        lower_mark = lower.get('mark', {}).get('type') if isinstance(lower.get('mark'), dict) else lower.get('mark')
        if lower_mark != 'bar':
            errors.append(f'FAIL: lower mark is {lower_mark}, expected bar')

        lower_enc = lower.get('encoding', {})
        lower_y = lower_enc.get('y', {}).get('field')
        lower_x = lower_enc.get('x', {})
        if lower_y != 'volume':
            errors.append(f'FAIL: lower y field is {lower_y}, expected volume')
        if lower_x.get('type') != 'temporal':
            errors.append(f'FAIL: lower x type is {lower_x.get(\"type\")}, expected temporal')
        if lower_x.get('field') != 'date':
            errors.append(f'FAIL: lower x field is {lower_x.get(\"field\")}, expected date')

        # 7. Interval selection parameter with encodings=['x']
        params = spec.get('params', [])
        brush_param = None
        for p in params:
            sel = p.get('select', {})
            if sel.get('type') == 'interval' and sel.get('encodings') == ['x']:
                brush_param = p
                break
        if not brush_param:
            errors.append('FAIL: no interval selection param with encodings=[\"x\"]')
        else:
            param_name = brush_param['name']
            # 8. Selection attached to lower view
            views = brush_param.get('views', [])
            lower_name = lower.get('name', '')
            if lower_name not in views:
                errors.append(f'FAIL: brush param views {views} does not include lower view name {lower_name}')

            # 9. Upper view x scale domain references the brush param
            upper_x_enc = upper.get('encoding', {}).get('x', {})
            upper_scale = upper_x_enc.get('scale', {})
            domain = upper_scale.get('domain', {})
            domain_param = domain.get('param', '')
            if domain_param != param_name:
                errors.append(f'FAIL: upper x scale domain param is {domain_param}, expected {param_name}')

if errors:
    print('VALIDATION ERRORS:')
    for e in errors:
        print(f'  - {e}')
else:
    print('ALL ACCEPTANCE CRITERIA PASSED')
"
